import openpyxl, sys, glob
sys.stdout.reconfigure(encoding="utf-8")

files = glob.glob("C:/Users/TUF/Downloads/*theo_NV*")
print("Found:", files)
wb = openpyxl.load_workbook(files[0])
ws = wb.active

nv_dict = {}
team_set = set()
for row in ws.iter_rows(min_row=2, values_only=True):
    ma_kh, ten_kh, chi_nhanh, team, ten_nv = row
    if ten_nv:
        key = str(ten_nv).strip()
        if key not in nv_dict:
            nv_dict[key] = {"team": team, "count": 0}
        nv_dict[key]["count"] += 1
    if team:
        team_set.add(team)

print("=== Teams ===")
for t in sorted(team_set):
    print("  Team " + str(t))

print()
print("=== Nhan vien sale (ten -> team -> so KH) ===")
for nv, info in sorted(nv_dict.items(), key=lambda x: (x[1]["team"], x[0])):
    print("  " + nv + " | Team " + str(info["team"]) + " | " + str(info["count"]) + " KH")

print()
print("Total: " + str(ws.max_row - 1) + " rows, " + str(len(nv_dict)) + " NV, " + str(len(team_set)) + " teams")

